// // This SR-flip-flop sets Q to 0 when S=1 and R=0, and resets Q to 1 when S=0 and R=1.
module sr_flip_flop (  
    input S,  
    input R,  
    input clk,  
    output reg Q  
);  

always @(posedge clk) begin  
    if (S && ~R)  
        Q <= 1;  
    else if (~S && R)  
        Q <= 0;  
    // If S and R are both 0, maintain the state (Q remains unchanged)  
    // If S and R are both 1, maintain the state (Q remains unchanged)  
end  
endmodule
